const authHeader = msg.req.headers.authorization || "";
const token = authHeader.startsWith("Bearer ") ? authHeader.split(' ')[1] : null;

if (!token) {
  msg.auth = false;
  msg.error_reason = "No Auth Token";
  return msg;
}

// Look up the device by the unique token the Pi received at registration
msg.params = [token];
msg.query = `SELECT device_id FROM devices WHERE auth_token = $1;`;
return msg;

// --- 1. Check if the DB found a token ---
if (!msg.payload || msg.payload.length === 0) {
    msg.auth = false;
    msg.error_reason = "Invalid Token";
    return msg;
}

const identity = msg.payload[0];

// --- 2. Simplified Authorization ---
// Since we no longer use /:device_id in the URL, 
// if the token is valid, the device is authorized for itself.
const isAdmin = (identity.access_level >= 3);
const isOwnDevice = true; // The token itself proves identity

msg.auth = isAdmin || isOwnDevice;

// --- 3. Context Passing ---
msg.authorized_identity = {
    role: isAdmin ? "admin" : "unit",
    device: identity.device_id
};

return msg;

let res = msg.res
msg = {}
