msg.status = 202
return msg;

const identity = msg.payload[0];

if (!identity) {
    msg.auth = false;
    msg.error_reason = "Token not recognized.";
    return [null, msg];
}

const data = msg.data;
const timestamp = data.timestamp || new Date().toISOString();
const nickname = data.nickname || null; // Extract the optional nickname

// Clean the JSON blob so it only contains raw sensor values
const sensor_payload = { ...data };
delete sensor_payload.timestamp;
delete sensor_payload.device_id;
delete sensor_payload.nickname;

// Update params and query to include the nickname column ($4)
msg.params = [
    identity.device_id,
    JSON.stringify(sensor_payload),
    timestamp,
    nickname
];

msg.query = `
    INSERT INTO measurements (device_id, data, recorded_at, nickname)
    VALUES ($1, $2::jsonb, $3, $4);
`;

return msg;

// Get the token from the browser's request
const authHeader = msg.req.headers.authorization || "";

// Forward the token to our internal API
msg.headers = {
    "Authorization": authHeader,
    "Content-Type": "application/json"
};

// Target our new unified query endpoint
msg.url = "http://127.0.0.1:1880/node/aqc/apiv1/external/query";
msg.method = "POST";

// We can pass filters here later if needed
msg.payload = {};

return msg;

const authHeader = msg.req.headers.authorization || "";
msg.token = authHeader.replace("Bearer ", "");
return msg;

// Data from the Pi's POST body
msg.serial = msg.payload.cpu_serial;
msg.nickname = msg.payload.nickname || "New Device";

// Data from the Authorization Header (already parsed in previous node)
msg.params = [msg.token, msg.serial];

msg.query = `
    SELECT 
        o.org_id, 
        o.remaining_devices,
        d.auth_token as existing_token,
        d.device_id
    FROM organizations o
    LEFT JOIN devices d ON d.cpu_serial = $2 AND d.org_id = o.org_id
    WHERE o.prov_token = $1;
`;

return msg;

const result = msg.payload[0];

// 1. Basic Validation
if (!result || !result.org_id) {
    msg.statusCode = 401;
    msg.payload = { status: "error", message: "Invalid Provisioning Token" };
    return [null, msg];
}

// 2. Prepare tokens
msg.auth_token = result.existing_token || crypto.randomBytes(24).toString('hex');
msg.is_new = !result.existing_token;

// 3. SCENARIO: Re-registration (Update existing)
if (result.existing_token) {
    msg.device_id = result.device_id;
    msg.query = "UPDATE devices SET nickname = $1 WHERE device_id = $2 RETURNING device_id;";
    msg.params = [msg.nickname, msg.device_id];
    return [msg, null];
}

// 4. SCENARIO: New Registration (The fix is here!)
if (result.remaining_devices <= 0) {
    msg.statusCode = 403;
    msg.payload = { status: "error", message: "No slots remaining." };
    return [null, msg];
}

// NOTICE: We do NOT include device_id in the columns or values list below.
// This allows the database sequence we created in Step 1 to take over.
msg.query = `
    INSERT INTO devices (org_id, cpu_serial, nickname, auth_token)
    VALUES ($1, $2, $3, $4)
    RETURNING device_id;
`;
msg.params = [result.org_id, msg.serial, msg.nickname, msg.auth_token];

return [msg, null];

const db_row = msg.payload[0];

// The DB-generated ID will be in db_row.device_id
if (!db_row || !db_row.device_id) {
    msg.statusCode = 500;
    msg.payload = { status: "error", message: "Database failed to generate ID." };
    return [null, msg];
}

msg.payload = {
    status: "success",
    token: msg.auth_token,
    device_id: db_row.device_id, // e.g., "aqc-1"
    new_registration: msg.is_new
};

return [msg, null];

const authHeader = msg.req.headers.authorization || "";

// 1. Token Verification
if (!authHeader.toLowerCase().startsWith("bearer ")) {
    msg.statusCode = 401;
    msg.payload = { error: "Authentication Required" };
    return [null, msg];
}

const token = authHeader.substring(7).trim();

// 2. Extract Date Filters from POST body
// If not provided, we pass null to the SQL query
const startDate = msg.payload.start_date || null;
const endDate = msg.payload.end_date || null;

// 3. Query Construction
// $1 & $2: Token check
// $3: Start Date filter
// $4: End Date filter
msg.params = [token, token, startDate, endDate];

msg.query = `
    WITH identity AS (
        SELECT 'device' as type, device_id, org_id 
        FROM devices WHERE auth_token = $1
        UNION ALL
        SELECT 'org' as type, NULL as device_id, org_id 
        FROM organizations WHERE prov_token = $2
    )
    SELECT 
        m.recorded_at, 
        m.device_id, 
        m.nickname AS device_nickname, 
        o.nickname AS org_nickname,
        m.data 
    FROM measurements m
    JOIN devices d ON m.device_id = d.device_id
    JOIN organizations o ON d.org_id = o.org_id
    JOIN identity i ON (i.type = 'device' AND m.device_id = i.device_id) 
                    OR (i.type = 'org' AND d.org_id = i.org_id)
    WHERE 
        ($3::timestamp IS NULL OR m.recorded_at >= $3::timestamp)
        AND ($4::timestamp IS NULL OR m.recorded_at <= $4::timestamp)
    ORDER BY m.recorded_at DESC
    LIMIT CASE 
        WHEN $3 IS NULL AND $4 IS NULL THEN 500 
        ELSE 5000 
    END;
`;

return [msg, null];
